function solve(n: number, edges: number[][], k: number): number {
    // Sort edges by time to process them in order
    edges.sort((a, b) => a[2] - b[2]);

    // Union-Find data structure to track connected components
    class UnionFind {
        parent: number[];
        rank: number[];

        constructor(size: number) {
            this.parent = [];
            this.rank = [];
            for (let i = 0; i < size; i++) {
                this.parent[i] = i;
                this.rank[i] = 1;
            }
        }

        find(x: number): number {
            if (this.parent[x] !== x) {
                this.parent[x] = this.find(this.parent[x]);
            }
            return this.parent[x];
        }

        union(x: number, y: number): boolean {
            const xRoot = this.find(x);
            const yRoot = this.find(y);

            if (xRoot === yRoot) {
                return false; // Already connected
            }

            if (this.rank[xRoot] < this.rank[yRoot]) {
                this.parent[xRoot] = yRoot;
            } else {
                this.parent[yRoot] = xRoot;
                if (this.rank[xRoot] === this.rank[yRoot]) {
                    this.rank[xRoot]++;
                }
            }
            return true;
        }
    }

    const uf = new UnionFind(n);
    let components = n; // Initially, each node is its own component

    // Process edges in order of increasing time
    for (const [u, v, time] of edges) {
        // If the nodes are not connected, merging them reduces the number of components
        if (uf.union(u, v)) {
            components--;
        }

        // Check if we have at least k components
        if (components <= k) {
            return time;
        }
    }

    // If we haven't found a time yet, return 0 (no edges need to be removed)
    return 0;
}

